public async Task<PaymentResult> ChargeWithRetry(decimal amount, string idempotencyKey)
{
    var policy = Policy<PaymentResult>
        .Handle<TimeoutException>()
        .Or<HttpRequestException>()
        .WaitAndRetryAsync(retryCount: 3, sleepDurationProvider: _ => TimeSpan.FromSeconds(2));

    return await policy.ExecuteAsync(async () =>
        await _paymentService.ChargeAsync(amount, idempotencyKey)
    );
}

