    .Or<HttpRequestException>()
    .FallbackAsync(async () => 
        await _cache.GetAsync($"rec:{userId}") ?? new Recommendation { IsStale = true }
    )
    .WrapAsync(
        Policy<Recommendation>
            .Handle<TimeoutException>()
            .CircuitBreakerAsync(handledEventsAllowedBeforeBreaking: 5, durationOfBreak: TimeSpan.FromSeconds(60))
    );

