public class Account
{
    private int _balance = 100;
    public void Deposit(int amount)
    {
        _balance = _balance + amount;  // Not atomic
    }
}

// ✅ GOOD — atomic and versioned
public class ResilientAccount
{
    private int _balance = 100;
    private int _version = 0;
    public bool Deposit(int amount, int expectedVersion)
    {
        lock (this)
        {
            if (_version != expectedVersion) return false;
            _balance += amount;
            _version++;
            return true;
        }
    }
}

