// ✅ GOOD — idempotency key + transactional outbox
public async Task ChargeAsync(PaymentRequest req) {
    var existing = await db.Payments
        .FirstOrDefaultAsync(p => p.IdempotencyKey == req.IdempotencyKey);
    if (existing != null) return existing;

    using (var tx = await db.Database.BeginTransactionAsync()) {
        var charge = await gateway.ChargeAsync(req.Amount);
        var payment = new Payment { 
            IdempotencyKey = req.IdempotencyKey,
            Amount = req.Amount 
        };
        db.Payments.Add(payment);
        db.OutboxEvents.Add(new OutboxEvent { 
            Type = "PaymentProcessed", Data = charge 
        });
        await db.SaveChangesAsync();
        await tx.CommitAsync();
    }
}

