app.MapPost("/api/data", async (HttpContext ctx, Repo db) => {
    var clientId = GetClientId(ctx);
    var breaker = circuitBreakers.GetOrAdd(clientId, 
        _ => new CircuitBreaker(failureThreshold: 10, timeout: TimeSpan.FromSeconds(30)));

    if (breaker.IsOpen) return Results.StatusCode(429);
    try {
        var data = await db.GetDataAsync();
        breaker.RecordSuccess();
        return Results.Ok(data);
    } catch {
        breaker.RecordFailure();
        return Results.StatusCode(500);
    }
});

// ❌ BAD — no graceful degradation, returns error immediately
public async Task<UserProfile> GetProfileAsync(string userId) {
    var preferences = await dependencyService.GetPreferencesAsync(userId);
    // If service is down, customer sees error, session lost
    return new UserProfile { Preferences = preferences };
}

// ✅ GOOD — circuit breaker + cache degradation
public async Task<UserProfile> GetProfileAsync(string userId) {
    var breaker = circuitBreaker.GetOrAdd("dependencies.preferences", 
        _ => new CircuitBreaker());

    if (breaker.IsOpen) {
        // Fall back to cache with staleness warning
        var cached = cache.Get<(UserPrefs prefs, DateTime time)>(userId);
        if (cached.HasValue) {
            var age = DateTime.UtcNow - cached.Value.time;
            return new UserProfile { 
                Preferences = cached.Value.prefs,
                Warning = $"Stale data ({age.TotalMinutes:F0} min old)"
            };
        }
        return new UserProfile { Warning = "Service unavailable, no cache" };
    }

    try {
        var prefs = await dependencyService.GetPreferencesAsync(userId);
        cache.Set(userId, (prefs, DateTime.UtcNow), TimeSpan.FromMinutes(5));
        return new UserProfile { Preferences = prefs };
    } catch {
        breaker.RecordFailure();
        // Retry: return cached or empty
    }
}

// ❌ BAD — reads may hit stale replica after write
public async Task<Order> CreateAndRetrieveOrderAsync(Order order) {
    // Write to primary
    await db.Orders.AddAsync(order);
    await db.SaveChangesAsync();

    // Read from replica—might not see the write yet!
    var retrieved = await replicaDb.Orders.FindAsync(order.Id);
    return retrieved; // Might be null or stale
}

// ✅ GOOD — read-after-write goes to primary
public async Task<Order> CreateAndRetrieveOrderAsync(Order order) {
    using (var tx = await db.Database.BeginTransactionAsync()) {
        await db.Orders.AddAsync(order);
        await db.SaveChangesAsync();

        // Read from same primary connection in same transaction
        var retrieved = await db.Orders.FindAsync(order.Id);
        await tx.CommitAsync();
        return retrieved;
    }

    // Non-critical historical reads use replica
    var stats = await replicaDb.Orders
        .Where(o => o.CreatedAt < DateTime.UtcNow.AddHours(-1))
        .CountAsync(); // Safe: historical data is definitely replicated
}

// ❌ BAD — no versioning, stale cache after schema change
public async Task<UserPreferences> GetPreferencesAsync(string userId) {
    var key = $"user:preferences:{userId}";
    var cached = cache.Get<UserPreferences>(key);
    if (cached != null) return cached;

    var prefs = await db.UserPreferences.FindAsync(userId);
    cache.Set(key, prefs); // No version, no TTL; stale forever if schema changes
    return prefs;
}

// ✅ GOOD — versioned key + TTL + explicit invalidation
public async Task<UserPreferences> GetPreferencesAsync(string userId) {
    const string version = "v2"; // Bump on schema change
    var key = $"user:preferences:{version}:{userId}";

    var cached = cache.Get<UserPreferences>(key);
    if (cached != null) return cached;

    var prefs = await db.UserPreferences.FindAsync(userId);
    cache.Set(key, prefs, TimeSpan.FromHours(1)); // TTL safety net
    return prefs;
}

public async Task InvalidateUserPreferencesAsync(string userId) {
    // Scan and delete all versions; pattern matching in Redis
    var keys = cache.GetKeysByPattern($"user:preferences:*:{userId}");
    foreach (var key in keys) {
        cache.Delete(key);
    }
}

// On-delete trigger invalidation
public async Task DeleteUserAsync(string userId) {
    await db.Users.Where(u => u.Id == userId).DeleteAsync();
    await InvalidateUserPreferencesAsync(userId);
    cache.Publish($"user:deleted:{userId}", userId); // Broadcast to all servers
}

// ❌ BAD — no prioritization, all requests treated equally
app.MapPost("/api/order", async (OrderRequest req) => {
    // Payment request competes with analytics query, both queued equally
    var order = await ProcessOrderAsync(req);
    await SendAnalyticsAsync(order); // Blocks payment until analytics finishes
    return order;
});

// ✅ GOOD — priority queue + graceful degradation
services.AddSingleton<PriorityQueue<RequestContext, int>>();
var queue = sp.GetRequiredService<PriorityQueue<RequestContext, int>>();

app.Use(async (ctx, next) => {
    var priority = GetRequestPriority(ctx.Request.Path);
    if (queue.Count > 1000) {
        if (priority == Priority.Low) {
            ctx.Response.StatusCode = 429;
            await ctx.Response.WriteAsync("Service overloaded, try later");
            return;
        }
    }

    var reqContext = new RequestContext { HttpContext = ctx };
    queue.Enqueue(reqContext, (int)priority);
    await next();
});

app.MapPost("/api/order", async (OrderRequest req) => {
    var order = await ProcessOrderAsync(req);
    // Analytics is degradable—skip under load
    if (!IsSystemOverloaded()) {
        await SendAnalyticsAsync(order);
    }
    return order;
});

int GetRequestPriority(string path) {
    return path switch {
        var p when p.Contains("login") => 1, // Critical
        var p when p.Contains("payment") => 1,
        var p when p.Contains("analytics") => 10, // Non-critical
        _ => 5
    };
}
